+    fn test_mmr_empty_results() {
+        let mmr = MmrReranker::new(0.5);
+        let result = mmr.rerank(&[1.0, 0.0], &[], 5);
+        assert!(result.is_empty());
+    }
+
+    #[test]
+    fn test_mmr_single_result() {
+        let mmr = MmrReranker::new(0.5);
