+mod tests {
+    use super::*;
+
+    #[test]
+    fn test_reranker_empty_results() {
+        let reranker = AttentionReranker::new(4, 1);
+        let result = reranker.rerank(&[1.0, 0.0, 0.0, 0.0], &[], 5);
+        assert!(result.is_empty());
+    }
+
+    #[test]
